var e=[{id:`L2_1`,type:`dialog`,speaker:null,text:{KOREA:`오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.`,JPN:`長い間悩んだ結果、あなたは一つ大事なことに気づいた。`,ENG:`After much debate, you came to the conclusion`,TWN:`苦惱許久後，你意識到一件重要的事實。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:null,text:{KOREA:`줄곧 생각해 온 그야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.`,JPN:`ずっと考えてきた彼だからこそ、これから向き合う運命に必ず必要な存在であることを。`,ENG:`that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.`,TWN:`經過長久的思考，你明白在今後即將面對的命運中，他是必不可少的存在。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`그리하여 당신은 결심했다.`,JPN:`そして、あなたは決心した。`,ENG:`So, you've decided`,TWN:`所以你下定決心。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그와 함께하기로.`,JPN:`この世界でどのような結末を迎えるとしても、最後まで彼とともにいることを。`,ENG:`that you'll be with him, no matter the consequences.`,TWN:`不管這個世界會迎來怎樣的結局，你都要和他一起走到最後。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:null,text:{KOREA:`마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.`,JPN:`意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。`,ENG:`Having decided that, you called him to your office. He said he'd be here soon.`,TWN:`做好心理準備後，你將他傳喚到老闆辦公室，他說馬上就會過來。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L12_1`,type:`dialog`,speaker:`RIFLE_STATE_NULL_NULL`,text:{KOREA:`사장님, 관리부에 전달 받은 대로 고용 계약을 갱신하러 왔습니다.`,JPN:`社長、管理部からの伝達を受け、雇用契約の更新に伺いました。`,ENG:`Boss, I came to renew my employment contract as the Managerial Department asked.`,TWN:`老闆，我們收到管理部的通知，來更新雇傭契約了。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`RIFLE_STATE_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`RIFLE_STATE_NULL_NULL`,text:{KOREA:`......`,JPN:`……`,ENG:`......`,TWN:`......`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`RIFLE_STATE_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`RIFLE_STATE_NULL_NULL`,text:{KOREA:`말씀하시는 취지는 알겠습니다.`,JPN:`お話の趣旨は理解いたしました。`,ENG:`I understand what you mean.`,TWN:`我們明白您說的話了。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`RIFLE_STATE_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`RIFLE_STATE_NULL_NULL`,text:{KOREA:`하지만 저희도 군인으로서, 기왕이면 병사들의 노고를 이해해 주는 상급자의 명령에 따르고 싶습니다.`,JPN:`我々も軍人として、せっかくなら兵士達の貢献を解ってくださる方の命令に従いたいのです。`,ENG:`But as soldiers, we'd like to follow the orders of our superiors who appreciate our hard work.`,TWN:`而作為軍人，我們也希望能夠服從理解士兵辛苦的上級。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`RIFLE_STATE_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`RIFLE_STATE_NULL_NULL`,text:{KOREA:`그러니 저희에게 명령해 주십시오.`,JPN:`ですので、どうか我々に命令を下してください。`,ENG:`So, please order us.`,TWN:`所以請對我們下命令吧。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`RIFLE_STATE_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`RIFLE_STATE_NULL_NULL`,text:{KOREA:`기꺼이 사장님을 따르도록 하겠습니다.`,JPN:`喜んで社長の命令に従わせていただきます。`,ENG:`We'll happily follow you, Boss.`,TWN:`我們很樂意跟隨老闆。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`RIFLE_STATE_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};